```ts
// src/db/database.server.ts
import Database from 'better-sqlite3';
import { mkdirSync } from 'node:fs';
import { dirname } from 'node:path';
import { createHash, randomUUID } from 'node:crypto';

const DB_PATH = '/home/user/qwik-wizard/db/app.db';
let db: Database.Database;

export function getDb() {
  if (!db) {
    mkdirSync(dirname(DB_PATH), { recursive: true });
    db = new Database(DB_PATH);
    db.pragma('journal_mode = WAL');
    db.exec(`
      CREATE TABLE IF NOT EXISTS users (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        email TEXT NOT NULL UNIQUE,
        password TEXT NOT NULL,
        full_name TEXT NOT NULL,
        age INTEGER NOT NULL,
        country TEXT NOT NULL
      );
    `);
    db.exec(`
      CREATE TABLE IF NOT EXISTS wizard_sessions (
        session_id TEXT PRIMARY KEY,
        data TEXT NOT NULL,
        updated_at INTEGER NOT NULL
      );
    `);
  }
  return db;
}

export function emailExists(email: string): boolean {
  const db = getDb();
  const row = db.prepare('SELECT 1 FROM users WHERE email = ? LIMIT 1').get(email.toLowerCase());
  return !!row;
}

export function insertUser(user: { email, password, fullName, age, country }) {
  const db = getDb();
  const hashed = hashPassword(password);
  db.prepare('INSERT INTO users (email, password, full_name, age, country) VALUES (?, ?, ?, ?, ?)').run(
    user.email.toLowerCase(), hashed, user.fullName, user.age, user.country
  );
}

function hashPassword(pw: string): string {
  // Use scrypt
  const salt = createHash('sha256').update('fixed-salt-' + pw).digest(); // no, use random salt
}
```

For password hashing, I'll use Node's `scrypt` (sync) with a random salt stored alongside. Format: `scrypt$salt$hash`. Use `randomBytes` for salt and `scryptSync`.

```ts
import { scryptSync, randomBytes, timingSafeEqual } from 'node:crypto';

export function hashPassword(password: string): string {
  const salt = randomBytes(16).toString('hex');
  const hash = scryptSync(password, salt, 64).toString('hex');
  return `scrypt$${salt}$${hash}`;
}
```

