```ts
export interface WizardData {
  email?: string;
  password?: string; // kept transiently for final insert; not displayed
  fullName?: string;
  age?: string | number;
  country?: string;
}

export function getProgress(sessionId: string): WizardData {
  const db = getDb();
  const row = db.prepare('SELECT data FROM wizard_sessions WHERE session_id = ?').get(sessionId) as { data: string } | undefined;
  if (!row) return {};
  try { return JSON.parse(row.data); } catch { return {}; }
}

export function saveProgress(sessionId: string, data: WizardData) {
  const db = getDb();
  const now = Date.now();
  db.prepare(`
    INSERT INTO wizard_sessions (session_id, data, updated_at) VALUES (?, ?, ?)
    ON CONFLICT(session_id) DO UPDATE SET data = excluded.data, updated_at = excluded.updated_at
  `).run(sessionId, JSON.stringify(data), now);
}

export function clearProgress(sessionId: string) {
  const db = getDb();
  db.prepare('DELETE FROM wizard_sessions WHERE session_id = ?').run(sessionId);
}
